CREATE TRIGGER tbiu_sc_lon_m_req_fund_ret
	BEFORE INSERT OR UPDATE ON sc_lon_m_req_fund_ret FOR EACH ROW
	EXECUTE PROCEDURE trigger_fct_tbiu_sc_lon_m_req_fund_ret();

